module RefModule(
  input signed [31:0] in,
  output reg [31:0] out
);// input is a 32-bit signed binary number
  wire [31:0] _tap_in = in & {32{1'b1}};

  // output is a 32-bit unsigned binary number

  always @(*) begin
    if (in < 0) begin
      out <= ~in + 1;
    end
    else begin
      out <= in;
    end
  end

endmodule
